{{Shrine |Name = Kuwado Shrine (鍬戸神社) |Image = {{Image needed|cat=三島市}} {{maplink2|frame=yes|plain=yes|type=point|marker=religious-shinto|zoom=12|frame-align=center|frame-width=250|coord={{coord|35|5|33.6|N|138|54|57|E}}}} |Location = {{ill|Shizuoka Prefecture|de|???|ja|静岡県|zh|???}} {{ill|Mishima City|de|???|ja|三島市|zh|???}} Nagabuse 1 |Coordinates = {{coord|35|5|33.6|N|138|54|57|E|region:JP-22_type:landmark|display=inline,title}} |Deity = {{ill|Shitori no Kami|de|???|ja|倭文神|zh|???}} (or unknown) |Rank = Former {{ill|village shrine|de|???|ja|村社|zh|???}}, {{ill|Shikinaisha|de|???|ja|式内社|zh|???}} |Foundation = |Main hall = |Alias = |Fuda-sho etc = |Annual festival = October 15 |Shinto rituals = |Map = {{Location map|Japan Shizuoka|label=Kuwado Shrine (鍬戸神社)|coordinates= {{coord2|35|5|33.6|N|138|54|57|E}}|position=bottom|width=200|mark=Shinto torii icon vermillion.svg|marksize=15|float=center|caption=}} }}
